/**
 * Типы авторизаций
 * @type {{STUDENT: string, EMPLOYER: string, NONE: string}}
 */
import axios from "axios";

const AUTH_TYPES = {
  STUDENT: 'student',
  EMPLOYER: 'employer',
  NONE: 'none',
}

/**
 * Обьект стостояния
 * @returns {{authType: AUTH_TYPES}}
 */
const stateObject = {
  authType: AUTH_TYPES.NONE,
}

const state = () => stateObject;

const getters = {
  /**
   * Авторизован пользовател или нет
   * @param {stateObject} state
   * @returns {boolean}
   */
  isAuth(state) {
    return [AUTH_TYPES.EMPLOYER, AUTH_TYPES.STUDENT].includes(state.authType);
  }
}

const actions = {
  /**
   * Задает тип авторизации
   * @param {Function} commit
   * @param {AUTH_TYPES} type
   */
  setAuthType({ commit }, type) {
    commit('setAuthType', type);
  },
  login({commit}, user){
    return new Promise((resolve, reject) => {
        // commit('auth_request')
        axios({url: 'http://localhost:3000/login', data: user, method: 'POST' })
          .then(resp => {
            const token = resp.data.token
            const user = resp.data.user
            localStorage.setItem('token', token)
            axios.defaults.headers.common['Authorization'] = token
            commit('auth_success', token, user)
            resolve(resp)
          })
          .catch(err => {
            commit('auth_error')
            localStorage.removeItem('token')
            reject(err)
          })
    })
  },
  // logout({commit}){},
}

const mutations = {
  /**
   * Задает тип авторизации
   * @param {stateObject} state
   * @param {AUTH_TYPES} type
   */
  setAuthType(state, type) {
    state.authType = type;
  },
}

const app = {
  namespaced: true,
  state,
  getters,
  actions,
  mutations,
}

export { app, AUTH_TYPES };
